"use strict";(self.webpackChunkleetcode=self.webpackChunkleetcode||[]).push([[7009],{3631:e=>{e.exports=JSON.parse('{"tag":{"label":"dynamic-programming","permalink":"/leetcode/docs/tags/dynamic-programming","allTagsPath":"/leetcode/docs/tags","count":16,"items":[{"id":"problems/knapsack","title":"0/1 Knapsack Problem","description":"You\'ve broken into an art gallery and want to maximize the value of the paintings you steal. All the paintings you steal you place in your bag which can hold at most W pounds. Given that the weight and value of the ith painting is given by weights[i] and values[i] respectively, return the maximum value you can steal.","permalink":"/leetcode/docs/problems/knapsack"},{"id":"problems/climbing-stairs","title":"Climbing Stairs","description":"This question is asked by Google. Given a staircase with N steps and the ability to climb either one or two steps at a time, return the total number of ways to arrive at the top of the staircase.","permalink":"/leetcode/docs/problems/climbing-stairs"},{"id":"problems/coin-change","title":"Coin Change","description":"This question is asked by Facebook. Given an array that represents different coin denominations and an amount of change you need to make, return the fewest number of coins it takes to make the given amount of change.","permalink":"/leetcode/docs/problems/coin-change"},{"id":"problems/decode-ways","title":"Decode Ways","description":"This question is asked by Microsoft. Given a message that is encoded using the following encryption method:","permalink":"/leetcode/docs/problems/decode-ways"},{"id":"problems/edit-distance","title":"Edit Distance (Levenshtein Distance)","description":"This question is asked by Google. Given two strings s and t, return the minimum number of operations needed to convert s into t where a single operation consists of inserting a character, deleting a character, or replacing a character.","permalink":"/leetcode/docs/problems/edit-distance"},{"id":"problems/frog-jump","title":"Frog Jump","description":"A frog is attempting to cross a river to reach the other side. Within the river, there are stones located at different positions given by a stones array (this array is in sorted order). Starting on the first stone (i.e. stones[0]), the frog makes a jump of size one potentially landing on the next stone. If the frog\'s last jump was of size x, the frog\'s next jump may be of size x - 1, x, or x + 1. Given these following conditions return whether or not the frog can reach the other side.","permalink":"/leetcode/docs/problems/frog-jump"},{"id":"problems/house-robber-binary-tree","title":"House Robber Binary Tree","description":"You\'re a thief trying to rob a binary tree. As a thief, you are trying to steal as much money as possible. The amount of money you steal is equivalent to the sum of all the node\'s values that you decide to rob. If two adjacent nodes are robbed, the authorities are automatically alerted. Return the maximum loot that you can steal without alerting the authorities.","permalink":"/leetcode/docs/problems/house-robber-binary-tree"},{"id":"problems/longest-common-subsequence","title":"Longest Common Subsequence","description":"This question is asked by Google. Given two strings, s and t, return the length of their longest subsequence.","permalink":"/leetcode/docs/problems/longest-common-subsequence"},{"id":"problems/min-cost-climbing-stairs","title":"Min Cost Climbing Stairs","description":"This question is asked by Apple. Given a staircase where the ith step has a non-negative cost associated with it given by cost[i], return the minimum cost of climbing to the top of the staircase. You may climb one or two steps at a time and you may start climbing from either the first or second step.","permalink":"/leetcode/docs/problems/min-cost-climbing-stairs"},{"id":"problems/minimum-path-sum","title":"Minimum Path Sum","description":"This question is asked by Google. Given an N\xd7M matrix, grid, where each cell in the matrix represents the cost of stepping on the current cell, return the minimum cost to traverse from the top-left hand corner of the matrix to the bottom-right hand corner.","permalink":"/leetcode/docs/problems/minimum-path-sum"},{"id":"problems/paint-house","title":"Paint House","description":"This question is asked by Apple. You are tasked with painting a row of houses in your neighborhood such that each house is painted either red, blue, or green. The cost of painting the ith house red, blue or green, is given by costsi, costsi, and costsi respectively. Given that you are required to paint each house and no two adjacent houses may be the same color, return the minimum cost to paint all the houses.","permalink":"/leetcode/docs/problems/paint-house"},{"id":"problems/palindrome-partitioning","title":"Palindrome Partitioning","description":"This question is asked by Google. Given a string s, return all possible partitions of s such that each substring is a palindrome.","permalink":"/leetcode/docs/problems/palindrome-partitioning"},{"id":"problems/predict-the-winner","title":"Predict the Winner","description":"This question is asked by Amazon. Given an integer array, two players take turns picking the largest number from the ends of the array. First, player one picks a number (either the left end or right end of the array) followed by player two. Each time a player picks a particular number, it is no longer available to the other player. This picking continues until all numbers in the array have been chosen. Once all numbers have been picked, the player with the larger score wins. Return whether or not player one will win.","permalink":"/leetcode/docs/problems/predict-the-winner"},{"id":"problems/two-city-scheduling","title":"Two City Scheduling","description":"This question is asked by Google. A company is booking flights to send its employees to its two satellite offices A and B. The cost of sending the ith employee to office A and office B is given by pricesi and pricesi respectively. Given that half the employees must be sent to office A and half the employees must be sent to office B, return the minimum cost the company must pay for all their employees\' flights.","permalink":"/leetcode/docs/problems/two-city-scheduling"},{"id":"problems/unique-paths","title":"Unique Paths","description":"This question is asked by Google. A ball is dropped into a special Galton board where at each level in the board the ball can only move right or down. Given that the Galton board has M rows and N columns, return the total number of unique ways the ball can arrive at the bottom right cell of the Galton board.","permalink":"/leetcode/docs/problems/unique-paths"},{"id":"problems/word-break","title":"Word Break","description":"This question is asked by Amazon. Given a string s and a list of words representing a dictionary, return whether or not the entirety of s can be segmented into dictionary words.","permalink":"/leetcode/docs/problems/word-break"}],"unlisted":false}}')}}]);